bootstrap();

#!/bin/sh set -e
# Подставляем API URL: заменяем захардкоженный localhost URL на относительный /api # чтобы nginx проксировал запросы к бэкенду API_URL="${API_BASE_URL:-/api}" find /usr/share/nginx/html -name '*.js' -exec sed -i "s|http://localhost:3003/api|${API_URL}|g" {} + find /usr/share/nginx/html -name '*.js' -exec sed -i "s|http://localhost:3000/api|${API_URL}|g" {} +
echo "API URL replaced with: ${API_URL}"

#!/bin/sh set -e
# Подставляем API URL: заменяем захардкоженный localhost URL на относительный /api # чтобы nginx проксировал запросы к бэкенду API_URL="${API_BASE_URL:-/api}" find /usr/share/nginx/html -name '*.js' -exec sed -i "s|http://localhost:3006/api|${API_URL}|g" {} +
echo "API URL replaced with: ${API_URL}"

server {
    listen 80;
    server_name localhost;
    root /usr/share/nginx/html;
    index index.html;

    # Проксирование API-запросов на бэкенд
    location /api/ {
        proxy_pass http://server:3000/api/;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    # Проксирование Socket.IO на бэкенд
    location /socket.io/ {
        proxy_pass http://server:3000/socket.io/;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 86400;
    }

    # Angular SPA — все остальные маршруты → index.html
    location / {
        try_files $uri $uri/ /index.html;
    }

    # Кеширование статики
    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }
}

